// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract GrandGooseMansion {
    uint256 public constant maxSupply = 10000;
    uint256 public constant preSaleWalletLimit = 10;
    uint256 public cost;
    uint256 public supply;
    mapping(address => uint256) public preSaleWalletMinted;
    address public owner;
    mapping(address => bool) public whitelist;
    enum SaleStatus { Paused, Presale, PublicSale }
    SaleStatus public currentSaleStatus = SaleStatus.Paused;
    bool private _notEntered;

    event Minted(address indexed user, uint256 amount);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the owner");
        _;
    }

    modifier nonReentrant() {
        require(!_notEntered, "ReentrancyGuard: reentrant call");
        _notEntered = true;
        _;
        _notEntered = false;
    }

    constructor(uint256 _cost) {
        owner = msg.sender;
        cost = _cost;
        _notEntered = true;
    }

    function isWhitelisted(address user) external view returns (bool) {
        return whitelist[user];
    }

    function whitelistUser(address user, bool status) external onlyOwner {
        whitelist[user] = status;
    }

    function startPresale() external onlyOwner {
        require(currentSaleStatus != SaleStatus.Presale, "Already started");
        currentSaleStatus = SaleStatus.Presale;
    }

    function startPublicSale() external onlyOwner {
        require(currentSaleStatus != SaleStatus.PublicSale, "Already started");
        currentSaleStatus = SaleStatus.PublicSale;
    }

    function setCost(uint256 newCost) external onlyOwner {
        cost = newCost;
    }

    function mintTokenWhitelisted(uint256 amount) external payable nonReentrant {
        require(currentSaleStatus == SaleStatus.Presale, "Presale not active");
